// AFU Dekanat - himoyalangan ma'lumotlar bazasi (AES shifrlangan)
const __DB_ENC = "";
const DEFAULT_DB = (function(){
  let pw = sessionStorage.getItem('afu_key') || '';
  for (let i = 0; i < 4; i++) {
    if (!pw) pw = prompt("AFU Dekanat platformasi\n\nParolni kiriting:") || '';
    if (!pw) continue;
    try {
      const b64 = CryptoJS.AES.decrypt(__DB_ENC, pw).toString(CryptoJS.enc.Utf8);
      if (!b64) throw new Error('parol xato');
      const db = JSON.parse(atob(b64));
      sessionStorage.setItem('afu_key', pw);
      window.__AFU_KEY = pw;
      return db;
    } catch(e) {
      sessionStorage.removeItem('afu_key');
      pw = '';
      if (i < 3) alert("Parol noto'g'ri. Qayta urinib ko'ring.");
    }
  }
  alert("Parol noto'g'ri kiritildi. Sahifani yangilab, qayta urinib ko'ring.");
  throw new Error("Parol noto'g'ri");
})();
